package com.example.demo.ui;import com.example.demo.dto.*;import com.example.demo.services.*;import com.vaadin.flow.component.combobox.ComboBox;import com.vaadin.flow.component.grid.Grid;import com.vaadin.flow.component.orderedlayout.VerticalLayout;import com.vaadin.flow.router.*;
@Route(value="lotes",layout=MainLayout.class)@PageTitle("Lotes | Franco")public class LotesView extends VerticalLayout{private final LoteService service;private final Grid<LoteProductoDTO>grid=new Grid<>(LoteProductoDTO.class,false);public LotesView(LoteService service,ProductoService productos){this.service=service;addClassName("content-view");setSizeFull();ComboBox<ProductoDTO>filter=new ComboBox<>("Producto");filter.setItems(productos.listar());filter.setItemLabelGenerator(ProductoDTO::nombre);filter.setClearButtonVisible(true);filter.addValueChangeListener(e->refresh(e.getValue()));grid.addColumn(LoteProductoDTO::producto).setHeader("Producto");grid.addColumn(l->l.codigoLote()==null?"-":l.codigoLote()).setHeader("Lote");grid.addColumn(LoteProductoDTO::fechaVencimiento).setHeader("Vencimiento");grid.addColumn(LoteProductoDTO::cantidadDisponible).setHeader("Disponible");grid.addColumn(LoteProductoDTO::estado).setHeader("Estado");add(ViewSupport.header("Lotes y vencimientos"),filter,grid);expand(grid);refresh(null);}private void refresh(ProductoDTO p){grid.setItems(p==null?service.proximosAVencer(3650):service.porProducto(p.id()));}}
